// BAD: block values are predictable and validator influenceable
// uint256 winner = uint256(keccak256(abi.encodePacked(block.timestamp, block.prevrandao))) % players.length;

// GOOD: request verifiable randomness from Chainlink VRF
import {VRFConsumerBaseV2Plus} from "@chainlink/contracts/src/v0.8/vrf/dev/VRFConsumerBaseV2Plus.sol";
import {VRFV2PlusClient} from "@chainlink/contracts/src/v0.8/vrf/dev/libraries/VRFV2PlusClient.sol";

contract Lottery is VRFConsumerBaseV2Plus {
    function drawWinner() external {
        // request randomness from the VRF coordinator (async)
        s_vrfCoordinator.requestRandomWords(VRFV2PlusClient.RandomWordsRequest({
            keyHash: keyHash,
            subId: subId,
            requestConfirmations: 3,
            callbackGasLimit: 200_000,
            numWords: 1,
            extraArgs: ""
        }));
    }

    function fulfillRandomWords(uint256, uint256[] calldata randomWords) internal override {
        // the VRF proof guarantees this value could not be predicted or biased
        uint256 winnerIndex = randomWords[0] % players.length;
        winner = players[winnerIndex];
    }
}
